// ═══════════════════════════════════════════════════════════════════════════════
// QUANTUM BACKTESTER — Node 1: Config Loader
// Reads parameters from Workflow Static Data.
// To configure: set these keys in the workflow's Static Data before running:
//   backtest_startDate       e.g. "2026-02-01"
//   backtest_endDate         e.g. "2026-04-04"
//   backtest_tickers         e.g. "TSLA,MSFT,NVDA,AMD"  (comma-sep, max 14)
//   backtest_slippageBps     e.g. 3   (basis points per side, default 3)
//   backtest_commPerShare    e.g. 0.005 (USD per share each way, default 0.005)
//   backtest_positionUSD     e.g. 5000 (USD per trade, default 5000)
//   backtest_maxHoldDays     e.g. 5   (max bars in trade, default 5)
// ═══════════════════════════════════════════════════════════════════════════════
const state   = $getWorkflowStaticData('global');
const POLYGON = state.POLYGON_API_KEY  || 'REDACTED_POLYGON_KEY';
const GROK    = state.GROK_API_KEY     || 'REDACTED_XAI_API_KEY';

const cfg = {
  startDate:       state.backtest_startDate   || '2026-02-01',
  endDate:         state.backtest_endDate     || '2026-04-04',
  tickers:        (state.backtest_tickers     || 'TSLA,NVDA,AMD,MSFT,RDDT,IONQ,BA,CVX,SMCI,HPE').split(',').map(t => t.trim().toUpperCase()),
  slippageBps:     Number(state.backtest_slippageBps   || 3),
  commPerShare:    Number(state.backtest_commPerShare   || 0.005),
  positionUSD:     Number(state.backtest_positionUSD   || 5000),
  maxHoldDays:     Number(state.backtest_maxHoldDays   || 5),
  biasEntry:   Number(state.backtest_biasEntry   || 62),
  biasExit:    Number(state.backtest_biasExit    || 45),
  minVolRatio: Number(state.backtest_minVolRatio || 0.5),
  maxAtrPct:   Number(state.backtest_maxAtrPct   || 8.0),
  POLYGON,
  GROK,
};

console.log('[BACKTEST-CONFIG] Running backtest:',
  cfg.startDate, '→', cfg.endDate,
  '|', cfg.tickers.length, 'tickers',
  '| slippage', cfg.slippageBps, 'bps',
  '| comm $', cfg.commPerShare, '/share'
);

// Emit one item per ticker so downstream nodes run in parallel
return cfg.tickers.map(ticker => ({ json: { ...cfg, ticker } }));

// QUANTUM BACKTESTER ENGINE v6
// Fixes: bias=55, NEUTRAL regime allowed, better config reading
// runOnceForAllItems mode
const configItems = $input.all();
const results = [];

// ── Helpers ──────────────────────────────────────────────────────────────────
function ema(arr, p) {
  if (!arr || !arr.length) return 0;
  const k = 2 / (p + 1); let e = Number(arr[0]) || 0;
  for (let i = 1; i < arr.length; i++) e = (Number(arr[i]) || e) * k + e * (1 - k);
  return e;
}
function mean(arr) { return arr.length ? arr.reduce((s,v) => s+v, 0) / arr.length : 0; }
function safeNum(v, fb) { const n = Number(v); return isFinite(n) ? n : (fb || 0); }

function mkBase(ticker, startDate, endDate) {
  return { ticker, execution:'STAND ASIDE', signal:'NEUTRAL', bias_score:'50',
    regime:'NEUTRAL', timeframe:'D', price:'0', volume_ratio:'1',
    strat_total_trades:0, strat_net_pct:'0', strat_win_rate:'0',
    strat_profit_factor:'0', strat_max_dd:'0',
    backtest_period: startDate+' to '+endDate, bars_used:0, _backtest_mode:true };
}

for (const configItem of configItems) {
  const cfg = configItem.json || {};
  const ticker = String(cfg.ticker || '');
  const POLYGON = String(cfg.POLYGON || 'REDACTED_POLYGON_KEY');
  const startDate = String(cfg.startDate || '2026-01-06');
  const endDate = String(cfg.endDate || '2026-04-04');

  // v6 configurable parameters
  const BIAS_ENTRY = safeNum(cfg.backtest_biasEntry, 55);
  const BIAS_EXIT  = safeNum(cfg.backtest_biasExit, 40);
  const MIN_VOL_RATIO = safeNum(cfg.backtest_minVolRatio, 0.3);
  const MAX_ATR_PCT = safeNum(cfg.backtest_maxAtrPct, 8.0);
  const slippageBps = safeNum(cfg.backtest_slippageBps, 3);
  const commPerShare = safeNum(cfg.backtest_commPerShare, 0.005);
  const positionUSD = safeNum(cfg.backtest_positionUSD, 5000);
  const maxHoldDays = safeNum(cfg.backtest_maxHoldDays, 5);

  if (!ticker) { 
    results.push({ json: mkBase('', startDate, endDate) }); 
    continue; 
  }

  // ── 1. Fetch daily bars ───────────────────────────────────────────────────
  let bars = [];
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.polygon.io/v2/aggs/ticker/' + ticker + '/range/1/day/' + startDate + '/' + endDate,
      qs: { adjusted:'true', sort:'asc', limit:5000, apiKey:POLYGON }, 
      json:true
    });
    bars = Array.isArray(raw && raw.results) ? raw.results : [];
  } catch (e) {
    results.push({ json: Object.assign(mkBase(ticker, startDate, endDate), { _error:'bars:'+String(e.message).slice(0,50) }) });
    continue;
  }

  if (bars.length < 25) {
    results.push({ json: Object.assign(mkBase(ticker, startDate, endDate), { _skip:'bars:'+bars.length, bars_used:bars.length }) });
    continue;
  }

  // ── 2. Simulate with improved entry/exit/sizing ───────────────────────────
  const tradePnls = [];
  let pos = null;

  for (let i = 22; i < bars.length; i++) {
    const bar = bars[i];
    if (!bar || typeof bar.c !== 'number' || bar.c <= 0) continue;

    const closes = bars.slice(i-19, i+1).map(b => (b && b.c > 0) ? b.c : 0).filter(v => v > 0);
    if (closes.length < 20) continue;

    const e5 = ema(closes.slice(-5), 5);
    const e20 = ema(closes, 20);
    const delta = e20 > 0 ? (e5 - e20) / e20 : 0;
    const bias = Math.round(Math.min(100, Math.max(0, 50 + delta * 500)));

    // Regime: TRENDING or NEUTRAL allowed (v6 change)
    const regime = Math.abs(delta) > 0.01 ? 'TRENDING' : 'NEUTRAL';

    // ATR (14-bar)
    const trBars = bars.slice(Math.max(0, i-14), i+1);
    const trs = trBars.slice(1).map((b,k) => {
      const prev = trBars[k];
      return (b && prev && b.h && b.l && prev.c) ? Math.max(b.h-b.l, Math.abs(b.h-prev.c), Math.abs(b.l-prev.c)) : 0;
    }).filter(v => v > 0);
    const atrVal = trs.length ? mean(trs) : bar.c * 0.02;
    const atrPct = bar.c > 0 ? (atrVal / bar.c) * 100 : 2;

    // Volume confirmation
    const volBars = bars.slice(Math.max(0, i-19), i+1);
    const avgVol = mean(volBars.map(b => safeNum(b && b.v)));
    const volRatio = avgVol > 0 ? safeNum(bar.v) / avgVol : 1;

    // ── Exit open position ──────────────────────────────────────────────────
    if (pos) {
      const hold = i - pos.ei;
      const isBull = pos.side === 'LONG';
      const exitByTime = hold >= maxHoldDays;
      const exitByReversal = isBull ? bias <= BIAS_EXIT : bias >= (100 - BIAS_EXIT);
      if (exitByTime || exitByReversal) {
        const slip = bar.c * slippageBps / 10000;
        const fill = isBull ? bar.c - slip : bar.c + slip;
        const comm = pos.sh * commPerShare * 2;
        const rawPnl = isBull ? (fill - pos.fill) * pos.sh : (pos.fill - fill) * pos.sh;
        tradePnls.push(safeNum(rawPnl - comm));
        pos = null;
      }
    }

    // ── Entry conditions ─────────────────────────────────────────────────────
    if (!pos) {
      if (atrPct > MAX_ATR_PCT) continue;
      if (volRatio < MIN_VOL_RATIO) continue;
      if (bias < BIAS_ENTRY && bias > (100 - BIAS_ENTRY)) continue;

      const isBullEntry = bias >= BIAS_ENTRY;
      const isBearEntry = bias <= (100 - BIAS_ENTRY);
      if (!isBullEntry && !isBearEntry) continue;

      const targetRiskPct = 2.0;
      const sizeMult = Math.min(1.0, targetRiskPct / Math.max(atrPct, 0.5));
      const adjUSD = positionUSD * sizeMult;
      const slip = bar.c * slippageBps / 10000;
      const fill = isBullEntry ? bar.c + slip : bar.c - slip;
      const sh = Math.max(1, Math.floor(adjUSD / (fill || 1)));
      pos = { side: isBullEntry ? 'LONG' : 'SHORT', ei: i, fill, sh };
    }
  }

  // ── 3. Performance statistics ─────────────────────────────────────────────
  const n = tradePnls.length;
  let strat_net_pct = '0', strat_win_rate = '0', strat_profit_factor = '0', strat_max_dd = '0';
  if (n > 0) {
    const wins = tradePnls.filter(v => v > 0);
    const gw = wins.reduce((s,v) => s+v, 0);
    const losses = tradePnls.filter(v => v <= 0);
    const gl = Math.abs(losses.reduce((s,v) => s+v, 0));
    const total = tradePnls.reduce((s,v) => s+v, 0);
    strat_net_pct = (total / positionUSD * 100).toFixed(2);
    strat_win_rate = (wins.length / n * 100).toFixed(1);
    strat_profit_factor = gl > 0 ? Math.min(10, gw / gl).toFixed(2) : (gw > 0 ? '10' : '0');
    let pk = 0, run = 0, dd = 0;
    for (const v of tradePnls) { 
      run += v; 
      if (run > pk) pk = run; 
      if (run - pk < dd) dd = run - pk; 
    }
    strat_max_dd = (Math.abs(dd) / positionUSD * 100).toFixed(2);
  }

  // ── 4. Current live signal ────────────────────────────────────────────────
  const lc = bars.slice(-25).map(b => (b && b.c > 0) ? b.c : 0).filter(v => v > 0);
  const lD = ema(lc, 20) > 0 ? (ema(lc.slice(-5),5) - ema(lc,20)) / ema(lc,20) : 0;
  const lBias = Math.round(Math.min(100, Math.max(0, 50 + lD * 500)));
  const lastBar = bars[bars.length-1];
  const lastC = lastBar && lastBar.c > 0 ? lastBar.c : 0;
  const lastATRPct = 2; // simplified for live signal
  const lRegime = Math.abs(lD) > 0.01 ? 'TRENDING' : 'NEUTRAL';
  const lAvgVol = mean(bars.slice(-20).map(b => safeNum(b&&b.v)));
  const lVolR = lAvgVol > 0 && lastBar && lastBar.v ? safeNum(lastBar.v)/lAvgVol : 1;

  let execution = 'STAND ASIDE', signal = 'NEUTRAL';
  if (lBias >= BIAS_ENTRY && lastATRPct <= MAX_ATR_PCT) {
    execution = 'BUY'; signal = 'BULLISH';
  } else if (lBias <= (100 - BIAS_ENTRY) && lastATRPct <= MAX_ATR_PCT) {
    execution = 'SELL'; signal = 'BEARISH';
  }

  results.push({ json: {
    ticker, execution, signal,
    bias_score: String(lBias),
    regime: lRegime,
    timeframe: 'D',
    price: String(lastC),
    volume_ratio: String(parseFloat(lVolR.toFixed(2))),
    strat_total_trades: n,
    strat_net_pct,
    strat_win_rate,
    strat_profit_factor,
    strat_max_dd,
    backtest_period: startDate + ' to ' + endDate,
    bars_used: bars.length,
    atr_pct: String(lastATRPct.toFixed(2)),
    _backtest_mode: true
  }});
}
return results;

// QUANTUM BACKTESTER AGGREGATOR v2
// Fixes: PF capped at 10 (no 99), min-trade filter (>=5), median stats,
//        honest per-ticker table, aligned with VC Gate field names

const results = $input.all().map(i => i.json);
const NL = '\n';

// Filter out tickers with insufficient data (< 5 trades)
const tradeable   = results.filter(r => parseInt(r.strat_total_trades || 0) >= 5);
const skipped     = results.filter(r => parseInt(r.strat_total_trades || 0) < 5);
const period      = results[0]?.backtest_period || '—';
const totalTrades = tradeable.reduce((s, r) => s + parseInt(r.strat_total_trades || 0), 0);

// Stats on valid tickers only
function avg(arr) { return arr.length ? arr.reduce((s,v)=>s+v,0)/arr.length : 0; }
function med(arr) {
  if (!arr.length) return 0;
  const s = [...arr].sort((a,b)=>a-b);
  const m = Math.floor(s.length/2);
  return s.length%2 ? s[m] : (s[m-1]+s[m])/2;
}

const nets  = tradeable.map(r => parseFloat(r.strat_net_pct  || 0));
const wrs   = tradeable.map(r => parseFloat(r.strat_win_rate  || 0));
const pfs   = tradeable.map(r => parseFloat(r.strat_profit_factor || 0)).filter(v => v > 0);
const dds   = tradeable.map(r => parseFloat(r.strat_max_dd    || 0));

const avgNet  = avg(nets).toFixed(2);
const medNet  = med(nets).toFixed(2);
const avgWR   = avg(wrs).toFixed(1);
const medPF   = med(pfs).toFixed(2);  // median PF more robust than mean
const avgDD   = avg(dds).toFixed(2);

// Sort by PF descending
const sorted  = tradeable.slice().sort((a,b) => parseFloat(b.strat_profit_factor||0) - parseFloat(a.strat_profit_factor||0));
const top3    = sorted.slice(0,3).map(r => '  ' + r.ticker + ': PF ' + r.strat_profit_factor + ' | WR ' + r.strat_win_rate + '% | Net ' + r.strat_net_pct + '%').join(NL);
const bottom3 = sorted.slice(-3).map(r => '  ' + r.ticker + ': PF ' + r.strat_profit_factor + ' | Net ' + r.strat_net_pct + '%').join(NL);

// Live signals from TRENDING tickers with PF >= 1.0
const actionable = tradeable.filter(r => r.execution !== 'STAND ASIDE' && parseFloat(r.strat_profit_factor||0) >= 1.0);
const signalLines = actionable.map(r => '  ' + (r.execution==='BUY'?'📈':'📉') + ' ' + r.ticker + ' ' + r.execution + ' bias=' + r.bias_score + ' PF=' + r.strat_profit_factor + ' ATR=' + r.atr_pct + '%').join(NL);

// Skipped tickers (too volatile / insufficient data)
const skipNote = skipped.map(r => r.ticker + '(' + (r._skip||r._error||'0T') + ')').join(', ');

let msg = '<b>📊 Backtest v5 — Improved Engine</b>' + NL;
msg += 'Period: ' + period + NL;
msg += 'Tradeable tickers: ' + tradeable.length + ' | Total trades: ' + totalTrades + NL;
if (skipNote) msg += 'Skipped: ' + skipNote + NL;
msg += NL;
msg += '<b>Portfolio stats (tradeable only):</b>' + NL;
msg += '  Avg Net: ' + avgNet + '% | Median: ' + medNet + '%' + NL;
msg += '  Avg WR: ' + avgWR + '% | Median PF: ' + medPF + NL;
msg += '  Avg MaxDD: ' + avgDD + '%' + NL + NL;
if (top3) { msg += '<b>Top (PF):</b>' + NL + top3 + NL + NL; }
if (bottom3) { msg += '<b>Bottom (PF):</b>' + NL + bottom3 + NL + NL; }
if (signalLines) {
  msg += '<b>Actionable signals (PF≥1.0 + TRENDING):</b>' + NL + signalLines + NL + NL;
} else {
  msg += '<b>Actionable signals:</b> None — neutral market or no tickers pass filters' + NL + NL;
}
msg += '<i>v5 fixes: bias≥65, TRENDING-only, ATR sizing, PF capped at 10, min 5 trades.</i>';

const BOT  = 'REDACTED_TELEGRAM_BOT_TOKEN';
const CHAT = 'REDACTED_CHAT_ID';
try {
  await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.telegram.org/bot'+BOT+'/sendMessage',
    headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ chat_id: CHAT, text: msg, parse_mode: 'HTML' })
  });
  console.log('[AGG v2] Telegram sent');
} catch(e) { console.log('[AGG v2] TG error:', e.message); }

return results.map(r => ({ json: r }));
